                </h3>
                <Badge variant="outline">{mockAlerts.length}</Badge>
              </div>

              <div className="space-y-3">
                {mockAlerts.map(alert => (
                  <AlertCard
                    key={alert.id}
                    alert={alert}
                    onAcknowledge={(id) => console.log('Acknowledged:', id)}
