                    <div className="font-mono text-xs">{format(new Date(Date.now() - 7200000), 'yyyy-MM-dd HH:mm')}Z</div>
                    <div className="mt-1">
                      Scheduled maintenance: GOES-18 magnetometer calibration 2025-09-13 02:00-04:00Z. Backup systems active.
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </div>
  );
}

